#include <vector>

std::vector<std::vector<long long>> solve(std::vector<std::vector<long long>> grid, long long x, long long y, long long k) {
    // Create a copy of the grid to avoid modifying the original
    std::vector<std::vector<long long>> matrix = grid;

    // Extract the submatrix
    std::vector<std::vector<long long>> submatrix;
    for (long long i = 0; i < k; ++i) {
        std::vector<long long> row;
        for (long long j = 0; j < k; ++j) {
            row.push_back(matrix[x + i][y + j]);
        }
        submatrix.push_back(row);
    }

    // Reverse the submatrix
    std::reverse(submatrix.begin(), submatrix.end());

    // Replace the original submatrix with the reversed one
    for (long long i = 0; i < k; ++i) {
        for (long long j = 0; j < k; ++j) {
            matrix[x + i][y + j] = submatrix[i][j];
        }
    }

    return matrix;
}
